-- Stores which canonical fields belong to which dimension.
-- Resolver merges: COMMON ∪ CORRIDOR(country|currency) ∪ SEGMENT ∪ COMBO
--
-- CARTRIDGE_CODE and PAYMENT_SCHEMA are identifier columns — they tag which
-- provider/schema a row belongs to (VISA vs DANDALION) but do NOT drive resolution.

CREATE TABLE FIELD_SET_CONFIG (
  ID             NUMBER GENERATED ALWAYS AS IDENTITY,
  CARTRIDGE_CODE VARCHAR2(50)   NOT NULL,
  PAYMENT_SCHEMA VARCHAR2(50)   NOT NULL,
  DIMENSION      VARCHAR2(20)   NOT NULL,
  DIMENSION_KEY  VARCHAR2(50)   NOT NULL,
  FIELD_NAME     VARCHAR2(100)  NOT NULL,
  ACTIVE         CHAR(1)        DEFAULT 'Y' NOT NULL,
  CREATED_AT     TIMESTAMP(6)   DEFAULT SYSTIMESTAMP NOT NULL,
  UPDATED_AT     TIMESTAMP(6)   DEFAULT SYSTIMESTAMP NOT NULL,
  CONSTRAINT PK_FIELD_SET_CONFIG PRIMARY KEY (ID),
  CONSTRAINT UK_FIELD_SET UNIQUE (CARTRIDGE_CODE, PAYMENT_SCHEMA, DIMENSION, DIMENSION_KEY, FIELD_NAME),
  CONSTRAINT CHK_FIELD_SET_DIMENSION CHECK (DIMENSION IN ('COMMON','CORRIDOR','SEGMENT','COMBO')),
  CONSTRAINT CHK_FIELD_SET_ACTIVE CHECK (ACTIVE IN ('Y','N'))
);

CREATE INDEX IDX_FSC_CARTRIDGE ON FIELD_SET_CONFIG (CARTRIDGE_CODE, PAYMENT_SCHEMA);
CREATE INDEX IDX_FSC_DIM_KEY ON FIELD_SET_CONFIG (DIMENSION, DIMENSION_KEY);

